create table view39_byfrom select hex(`from`) as hex_from,tx_category,hex(bytes4) as hex_bytes4,status,revertreason,count(*) as cnt,sum(gasfee) as sum_gasfee from x402txs_base group by `from`,tx_category,bytes4,status,revertreason;

create table view39_byx402to select hex(`x402_to`) has hex_x402_to,hex(`from`) as hex_from,count(*) as cnt,sum(x402_value) as sum_x402_value from x402txs_base where `status`=1 and tx_category='x' group by x402_to,`from`;

create table view39_byday select (`timestamp` DIV 86400) as day,count(*) as cnt,sum(gasfee) as sum_gasfee,sum(x402_value) as sum_x402_value from x402txs_base where `status`=1 and tx_category='x' group by day;

create table view39_byday_from select (`timestamp` DIV 86400) as day,hex(`from`) as hex_from,count(*) as cnt,sum(gasfee) as sum_gasfee,sum(x402_value) as sum_x402_value from x402txs_base where `status`=1 and tx_category='x' group by day,hex_from;

create table view39_byday_x402to select (`timestamp` DIV 86400) as day,hex(`x402_to`) as hex_x402_to,count(*) as cnt,sum(gasfee) as sum_gasfee,sum(x402_value) as sum_x402_value from x402txs_base where `status`=1 and tx_category='x' group by day,hex_x402_to;

create table view39_raw_reverted select * from x402txs_base where status=0;

